import Mathlib

theorem erdos312_constant_ceiling_bridge : ∀ c : ℝ, 30 * Real.log 15 / 59 < c → ∃ K : ℝ, 1 < K ∧ K < 59 / 30 ∧ Real.exp (-(c * K)) ≤ 1 / 15 := by
  intro c hc;
  -- Choose $K$ such that $1 < K < \frac{59}{30}$ and $c * K > \log 15$.
  obtain ⟨K, hK⟩ : ∃ K : ℝ, 1 < K ∧ K < 59 / 30 ∧ c * K > Real.log 15 := by
    -- Choose $K$ such that $1 < K < \frac{59}{30}$ and $c * K > \log 15$. Since $c > \frac{30 \log 15}{59}$, we can choose $K$ close enough to $\frac{59}{30}$ to satisfy this inequality.
    have hK_exists : Filter.Tendsto (fun K : ℝ => c * K) (nhdsWithin (59 / 30) (Set.Iio (59 / 30))) (nhds (c * (59 / 30))) := by
      exact tendsto_const_nhds.mul inf_le_left;
    have := hK_exists.eventually ( lt_mem_nhds <| show c * ( 59 / 30 ) > Real.log 15 by linarith ) ; have := this.and ( Ioo_mem_nhdsLT <| show 1 < 59 / 30 by norm_num ) ; obtain ⟨ K, hK₁, hK₂ ⟩ := this.exists ; exact ⟨ K, hK₂.1, hK₂.2, hK₁ ⟩ ;
  exact ⟨ K, hK.1, hK.2.1, by rw [ one_div, ← Real.log_le_log_iff ( by positivity ) ( by positivity ), Real.log_inv, Real.log_exp ] ; linarith ⟩

