theorem bounded_step_prefix : ∀ (xs : List ℚ) (η : ℚ), 0 < η → (∀ x ∈ xs, 0 ≤ x ∧ x ≤ η) → 1 < xs.sum → ∃ k : ℕ, k ≤ xs.length ∧ 1 - η < (xs.take k).sum ∧ (xs.take k).sum ≤ 1 := by
  intro xs η hη_pos h_bound h_sum
  have h_exists_k : ∃ k ≤ xs.length, (List.take k xs).sum > 1 := by
    exact ⟨ xs.length, le_rfl, by simpa using h_sum ⟩;
  -- Let's take the smallest such $k$.
  obtain ⟨k, hk_le, hk_gt⟩ : ∃ k ≤ xs.length, (List.take k xs).sum > 1 ∧ ∀ j < k, (List.take j xs).sum ≤ 1 := by
    exact ⟨ Nat.find h_exists_k, Nat.find_spec h_exists_k |>.1, Nat.find_spec h_exists_k |>.2, fun j hj => not_lt.1 fun contra => Nat.find_min h_exists_k hj ⟨ Nat.le_trans ( Nat.le_of_lt hj ) ( Nat.find_spec h_exists_k |>.1 ), contra ⟩ ⟩;
  rcases k with ( _ | k ) <;> simp_all +decide [ List.take ];
  exact ⟨ k, by linarith, by linarith [ h_bound ( xs[k] ) ( by simp ), hk_gt.2 k le_rfl ], by linarith [ h_bound ( xs[k] ) ( by simp ), hk_gt.2 k le_rfl ] ⟩

