import Mathlib

/-- A red/blue colouring of the edges of a finite complete graph, represented by
its red graph (the blue graph is its complement). -/
structure TwoColoring where
  Vertex : Type
  [fintypeVertex : Fintype Vertex]
  redGraph : SimpleGraph Vertex

attribute [instance] TwoColoring.fintypeVertex

/-- The largest red clique in a two-colouring. -/
noncomputable def redCliqueNumber (G : TwoColoring) : ℕ := G.redGraph.cliqueNum

/-- The largest blue clique in a two-colouring. -/
noncomputable def blueCliqueNumber (G : TwoColoring) : ℕ := G.redGraphᶜ.cliqueNum

/-- The lexicographic product of two graphs. -/
def lexGraphProduct {α β : Type} (G : SimpleGraph α) (H : SimpleGraph β) :
    SimpleGraph (α × β) :=
  SimpleGraph.fromRel fun x y => G.Adj x.1 y.1 ∨ (x.1 = y.1 ∧ H.Adj x.2 y.2)

/-- The lexicographic product colouring: compare first coordinates first, and use
    the second colouring only within a first-coordinate fibre. -/
def lexColorProduct (G H : TwoColoring) : TwoColoring where
  Vertex := G.Vertex × H.Vertex
  redGraph := lexGraphProduct G.redGraph H.redGraph

lemma cliqueNum_lexGraphProduct_le {α β : Type} [Fintype α] [Fintype β]
    (G : SimpleGraph α) (H : SimpleGraph β) :
    (lexGraphProduct G H).cliqueNum ≤ G.cliqueNum * H.cliqueNum := by
  by_contra h;
  obtain ⟨S, hS⟩ : ∃ S : Set (α × β), S.Finite ∧ S.ncard > G.cliqueNum * H.cliqueNum ∧ (lexGraphProduct G H).IsClique S := by
    contrapose! h;
    refine' csSup_le' _;
    rintro n ⟨ s, hs ⟩;
    exact le_of_not_gt fun hn => h (s : Set (α × β)) ( Finset.finite_toSet s ) ( by simpa [ ← Set.ncard_coe_finset ] using hn.trans_le ( by simpa [ ← Set.ncard_coe_finset ] using hs.2.ge ) ) ( by simpa [ ← Set.ncard_coe_finset ] using hs.1 );
  -- Take a maximum clique S in the lexicographic product. Its projection T onto alpha is a G-clique.
  obtain ⟨T, hT⟩ : ∃ T : Set α, T.Finite ∧ T.ncard ≤ G.cliqueNum ∧ ∀ x ∈ S, x.1 ∈ T := by
    refine' ⟨ S.image Prod.fst, Set.toFinite _, _, _ ⟩;
    · refine' le_csSup _ _;
      · exact ⟨ Fintype.card α, fun n hn => by obtain ⟨ s, hs ⟩ := hn; exact hs.card_eq ▸ Finset.card_le_univ _ ⟩;
      · refine' ⟨ _, _, _ ⟩;
        exact Set.Finite.toFinset ( hS.1.image Prod.fst );
        · intro x hx y hy hxy; have := hS.2.2; simp_all +decide ;
          obtain ⟨ a, ha ⟩ := hx; obtain ⟨ b, hb ⟩ := hy; have := hS.2.2 ha hb; simp_all +decide [ lexGraphProduct ] ;
          tauto;
        · rw [ ← Set.ncard_coe_finset ] ; aesop;
    · exact fun x hx => Set.mem_image_of_mem _ hx;
  -- Partition S into fibers over x in T. Each fiber's second-coordinate projection is an H-clique, and because first coordinate is fixed it has the same cardinality as the fiber.
  have h_fibers : ∀ x ∈ T, (Set.image Prod.snd (S ∩ {y | y.1 = x})).ncard ≤ H.cliqueNum := by
    intro x hx
    have h_fiber : ∀ y1 y2 : β, y1 ∈ Set.image Prod.snd (S ∩ {y | y.1 = x}) → y2 ∈ Set.image Prod.snd (S ∩ {y | y.1 = x}) → y1 ≠ y2 → H.Adj y1 y2 := by
      simp_all +decide [ Set.Pairwise, lexGraphProduct ];
      intro y1 y2 hy1 hy2 hy3; specialize hS; have := hS.2.2 x y1 hy1 x y2 hy2; simp_all +decide [ SimpleGraph.adj_comm ] ;
    refine' le_csSup _ _;
    · exact ⟨ Fintype.card β, fun n hn => by obtain ⟨ s, hs ⟩ := hn; exact hs.card_eq ▸ Finset.card_le_univ _ ⟩;
    · refine' ⟨ _, _, _ ⟩;
      exact Set.Finite.toFinset ( show Set.Finite ( Prod.snd '' ( S ∩ { y | y.1 = x } ) ) from Set.Finite.image _ ( hS.1.subset ( Set.inter_subset_left ) ) );
      · intro y1 hy1 y2 hy2 hy; aesop;
      · exact Eq.symm
          (Set.ncard_eq_toFinset_card (Prod.snd '' (S ∩ {y | y.1 = x}))
            (Set.Finite.image Prod.snd
              (Set.Finite.subset hS.left Set.inter_subset_left)));
  -- Thus |S| is the sum of at most |T| fibers, each at most H.cliqueNum, and |T| ≤ G.cliqueNum.
  have h_sum_fibers : S.ncard ≤ ∑ x ∈ hT.left.toFinset, (Set.image Prod.snd (S ∩ {y | y.1 = x})).ncard := by
    have h_sum_fibers : S.ncard ≤ ∑ x ∈ hT.left.toFinset, (S ∩ {y | y.1 = x}).ncard := by
      have h_sum_fibers : S.ncard = (⋃ x ∈ hT.left.toFinset, S ∩ {y | y.1 = x}).ncard := by
        congr with x ; aesop;
      rw [h_sum_fibers];
      exact Finset.set_ncard_biUnion_le hT.left.toFinset
        fun i => S ∩ {y | y.1 = i};
    convert h_sum_fibers using 2;
    rw [ Set.InjOn.ncard_image ] ; intro x hx y hy ; aesop;
  refine' hS.2.1.not_ge ( h_sum_fibers.trans _ );
  refine' le_trans ( Finset.sum_le_sum fun x hx => h_fibers x <| by simpa using hx ) _;
  simp_all +decide;
  exact Nat.mul_le_mul_right _ ( by simpa [ ← Set.ncard_coe_finset ] using hT.2.1 )

lemma compl_lexGraphProduct (G H : TwoColoring) :
    (lexGraphProduct G.redGraph H.redGraph)ᶜ =
      lexGraphProduct G.redGraphᶜ H.redGraphᶜ := by
  ext ⟨ u, v ⟩ ⟨ x, y ⟩ ; simp +decide [ lexGraphProduct ] ;
  by_cases hu : u = x <;> by_cases hv : v = y <;> simp +decide [ hu, hv, SimpleGraph.adj_comm ];
  grind

theorem lexicographicProduct_cliqueCaps : ∀ {a b c d : ℕ} {G H : TwoColoring}, redCliqueNumber G < a → blue

