theorem bounded_step_prefix : ∀ (xs : List ℚ) (η : ℚ), 0 < η → (∀ x ∈ xs, 0 ≤ x ∧ x ≤ η) → 1 < xs.sum → ∃ k : ℕ, k ≤ xs.length ∧ 1 - η < (xs.take k).sum ∧ (xs.take k).sum ≤ 1 := by
  intros xs η hη h_bound h_sum
  induction' xs using List.reverseRecOn with xs ys ih generalizing η;
  · norm_num at h_sum;
  · by_cases h_sum : 1 < xs.sum;
    · obtain ⟨ k, hk₁, hk₂, hk₃ ⟩ := ih η hη ( fun x hx => h_bound x ( List.mem_append_left _ hx ) ) h_sum; use k; simp_all +decide [ List.take_append ] ;
      linarith;
    · simp_all +decide [ List.sum_append ];
      exact ⟨ xs.length, by linarith, by simpa using by linarith [ h_bound ys ( Or.inr rfl ) ], by simpa ⟩

