theorem bounded_step_prefix : ∀ (xs : List ℚ) (η : ℚ), 0 < η → (∀ x ∈ xs, 0 ≤ x ∧ x ≤ η) → 1 < xs.sum → ∃ k : ℕ, k ≤ xs.length ∧ 1 - η < (xs.take k).sum ∧ (xs.take k).sum ≤ 1 := by
  intro xs η hη_pos hη_le hsum_gt_one
  obtain ⟨k, hk⟩ : ∃ k ≤ xs.length, (List.take k xs).sum ≤ 1 ∧ (List.take (k + 1) xs).sum > 1 := by
    contrapose! hsum_gt_one;
    have h_ind : ∀ k ≤ xs.length, (List.take k xs).sum ≤ 1 := by
      intro k hk; induction' k with k ih <;> norm_num at *;
      exact hsum_gt_one k hk.le ( ih hk.le );
    simpa using h_ind xs.length le_rfl;
  refine' ⟨ k, hk.1, _, hk.2.1 ⟩;
  cases h : xs[k]? <;> simp_all +decide [ List.take_add_one ];
  · linarith;
  · linarith [ hη_le _ ( show ‹_› ∈ xs from by rw [ List.getElem?_eq_some_iff ] at h; aesop ) ]

