/-- The standard binomial two-colour Ramsey bound. -/
def ramsey2 (s t : ℕ) : ℕ := (s + t - 2).choose (s - 1)

theorem ramsey_twoColor_le_add : ∀ s t : ℕ, 2 ≤ s → 2 ≤ t → ramsey2 s t ≤ ramsey2 (s - 1) t + ramsey2 s (t - 1) := by
  unfold ramsey2;
  rintro ( _ | _ | s ) ( _ | _ | t ) <;> simp +arith +decide [ Nat.choose ] at *

